import{c as t,Q as i,j as o,m as a}from"./chunks/framework.CdiUUa3G.js";const g=JSON.parse('{"title":"ADR-053 — Fleet imagery: hero, anatomy SVG, mission patch, crew portrait sourcing","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-053.md","filePath":"adr/ADR-053.md"}'),s={name:"adr/ADR-053.md"};function r(n,e,l,c,d,h){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-053-—-fleet-imagery-hero-anatomy-svg-mission-patch-crew-portrait-sourcing" tabindex="-1">ADR-053 — Fleet imagery: hero, anatomy SVG, mission patch, crew portrait sourcing <a class="header-anchor" href="#adr-053-—-fleet-imagery-hero-anatomy-svg-mission-patch-crew-portrait-sourcing" aria-label="Permalink to &quot;ADR-053 — Fleet imagery: hero, anatomy SVG, mission patch, crew portrait sourcing&quot;">​</a></h1><blockquote><p>Status · Accepted (retrospective; shipped v0.6.0) Date · 2026-05-15 Closes · RFC-016 OQ-3, OQ-8, OQ-13, OQ-18 TA anchor · §components/fleet/imagery · §constraints/provenance Related ADRs · ADR-035 (diagram authoring pipeline), ADR-046 (agency-first imagery), ADR-047 (provenance manifests + license stewardship), ADR-051 (outbound learn-link stewardship)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Every fleet entry needs four kinds of imagery:</p><ol><li><strong>Hero photo</strong> — one card-grid thumbnail per entry (137 entries).</li><li><strong>ANATOMY SVG</strong> — hand-authored cutaway/exploded diagram (~35 entries shipped at v0.6; rest no-op the tab).</li><li><strong>Mission patch</strong> — per notable flight (3–6 flights × ~30 crewed-spacecraft entries ≈ 120 patches).</li><li><strong>Crew portrait</strong> — per crew member on each notable flight (~400 portraits at full coverage).</li></ol><p>The naive path — pull whatever Google Images returns — produces three predictable failures: (a) artist&#39;s impressions get mistaken for photographs; (b) non-US programs end up represented by Western-press renderings instead of Roscosmos / CNSA / JAXA / ISRO releases; (c) crew portraits skew toward famous astronauts while flight-engineer mission specialists go missing entirely. ADR-046 established <strong>agency-first sourcing</strong> for the rest of the corpus; this ADR applies the same discipline to the four asset classes above and adds the SVG authoring rule from ADR-035 to the anatomy diagrams.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="hero-photo-sourcing-closes-oq-8" tabindex="-1">Hero photo sourcing (closes OQ-8) <a class="header-anchor" href="#hero-photo-sourcing-closes-oq-8" aria-label="Permalink to &quot;Hero photo sourcing (closes OQ-8)&quot;">​</a></h3><p><strong>Source priority</strong> (same as ADR-046, restated here so curators have it in one place):</p><ol><li><strong>Operating agency&#39;s published archive</strong> — NASA Image and Video Library, ESA, Roscosmos, CNSA, JAXA Digital Archives, ISRO, KARI, MBRSC, CSA, ASI. Each entry&#39;s <code>country</code>/<code>agency</code> fields drive the lookup.</li><li><strong>Wikimedia Commons</strong> — only when the agency archive is unavailable or doesn&#39;t publish the era&#39;s imagery (mid-century Soviet, etc.). Must be a CC-BY / CC-BY-SA / PD-Gov / PD-Soviet license.</li><li><strong><code>airandspacehistory.com</code></strong> — first-party permission granted for restricted Soviet-era imagery (closes OQ-18). Cited as <code>source: &quot;airandspacehistory.com&quot;</code> in <code>source-logos.json</code>; per-image waiver tracked in <code>license-waivers.json</code> per ADR-047.</li></ol><p><strong>Banned sources:</strong></p><ul><li>Artist&#39;s impressions of vehicles that exist or existed (per ADR-046; an <code>artistic-impression: true</code> flag exists in <code>license-waivers.json</code> for planned-only entries like <code>starship-hls</code>, <code>dream-chaser</code>, where no flown vehicle exists yet).</li><li>Render mockups from third-party publishers (no <code>wired.com</code>, no <code>space.com</code>).</li><li>Anything without a license file row in <code>static/data/image-provenance.json</code> (fail-closed per ADR-047).</li></ul><p><strong>Path convention:</strong> <code>static/images/fleet-galleries/&lt;id&gt;/01.jpg</code> (hero), <code>02.jpg</code>–<code>NN.jpg</code> (gallery). Manifest at <code>static/data/fleet-galleries.json</code> lists the slot order + caption per image.</p><h3 id="anatomy-svg-closes-oq-13" tabindex="-1">Anatomy SVG (closes OQ-13) <a class="header-anchor" href="#anatomy-svg-closes-oq-13" aria-label="Permalink to &quot;Anatomy SVG (closes OQ-13)&quot;">​</a></h3><p>Each fleet entry that ships an ANATOMY tab carries a single SVG at <code>static/diagrams/fleet/&lt;id&gt;.svg</code>. <strong>Hand-authored</strong> per the ADR-035 rule: source committed (the SVG file <em>is</em> the source), no AI generation, palette matches the Orrery canonical colour scheme (<code>/science</code> palette: deep navy background, gold + silver accents, magenta highlights, mono labels).</p><p><strong>Tiered rollout</strong> (closes OQ-13):</p><ul><li><strong>F.1 — Marquee entries (~20 SVGs):</strong> Saturn V, Apollo CSM Block II, Apollo LM, Soyuz-MS, Falcon 9, Crew Dragon, Space Shuttle Orbiter, ISS, Tiangong, Hubble, JWST, Curiosity, Perseverance, Voyager 1/2, Cassini, Viking 1, Lunokhod 1, Chang&#39;e 5, Chandrayaan-3 Vikram.</li><li><strong>F.2 — Family complements (~15 SVGs):</strong> other Soyuz generations, Mercury, Gemini, Skylab, Saturn IB, Atlas V, Long March 5, Ariane 5, Sokol-KV-2, A7L, etc.</li><li><strong>F.3 / F.4 — Long tail:</strong> ship as content authoring continues post-v0.6.</li></ul><p>ANATOMY tab <strong>no-ops gracefully</strong> when an entry has no SVG yet (closes RFC-016 OQ-4): the tab is hidden, the panel shrinks, no broken-image placeholder ever renders. At v0.6.0 the corpus has ~35 SVGs committed; ~100 entries no-op the tab.</p><p><strong>Validation:</strong> <code>scripts/validate-diagrams.ts</code> checks that every entry referencing <code>anatomy_svg: true</code> has the file on disk and the file is parseable XML; missing SVG fails the build.</p><h3 id="mission-patch-sourcing-closes-oq-3" tabindex="-1">Mission patch sourcing (closes OQ-3) <a class="header-anchor" href="#mission-patch-sourcing-closes-oq-3" aria-label="Permalink to &quot;Mission patch sourcing (closes OQ-3)&quot;">​</a></h3><p>Mission patches are first-party agency assets (NASA, Roscosmos, JAXA, ESA, CNSA, ISRO publish their own). Path convention: <code>static/images/missions/&lt;mission_id&gt;-patch.png</code>. Manifest row in <code>image-provenance.json</code> per ADR-047 — same fail-closed pipeline as hero photos.</p><p>Where the operating agency doesn&#39;t publish a patch (most uncrewed missions; some early Soviet flights), the entry&#39;s <code>flights[i].patch_path</code> is omitted; the panel renders the flight without a patch.</p><p>Wikimedia Commons is acceptable when it carries the agency&#39;s official patch under a free license (frequently does — patches are designed to be widely reproduced).</p><h3 id="crew-portrait-sourcing-closes-oq-3" tabindex="-1">Crew portrait sourcing (closes OQ-3) <a class="header-anchor" href="#crew-portrait-sourcing-closes-oq-3" aria-label="Permalink to &quot;Crew portrait sourcing (closes OQ-3)&quot;">​</a></h3><p><strong>Source priority for crew portraits:</strong></p><ol><li><strong>Official agency portrait</strong> (NASA &quot;official&quot; astronaut headshots; equivalent ESA / Roscosmos / CNSA / JAXA / ISRO releases). Path: <code>static/images/crew/&lt;surname&gt;-&lt;initial&gt;.jpg</code>. Always preferred — these are explicitly licensed for editorial use.</li><li><strong>Wikimedia Commons</strong> when no agency portrait exists at modern resolution (most early Soviet cosmonauts; some 1960s NASA mercury/gemini astronauts).</li><li><strong>In-flight crew photos</strong> as a last resort, cropped to a portrait aspect ratio. Provenance row records the crop in <code>notes</code>.</li></ol><p><strong>No crew portrait fallback:</strong> when no licensed portrait exists, the crew member renders as a name + role without an image. The panel does not display a silhouette placeholder — empty space is more honest than a generic avatar that implies &quot;this person exists but we couldn&#39;t find them&quot;.</p><p><code>scripts/audit-fleet-heroes.ts</code> + <code>scripts/fix-fleet-heroes.ts</code> were the bulk-audit tools used in v0.6 Phase F to flag low-quality heroes and substitute agency-archive equivalents; their output lives in <code>docs/provenance/fleet-hero-audit.md</code> and the Wikipedia-API filename derivation pattern they used is the canonical example for future audit passes.</p><h3 id="build-time-integrity" tabindex="-1">Build-time integrity <a class="header-anchor" href="#build-time-integrity" aria-label="Permalink to &quot;Build-time integrity&quot;">​</a></h3><p>All four image classes route through the <strong>same fail-closed validation</strong> locked by ADR-047:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fetch-assets → build-image-provenance → validate-data</span></span></code></pre></div><p>Every image referenced from a fleet entry (<code>hero_path</code>, <code>gallery[*].path</code>, <code>flights[i].patch_path</code>, <code>flights[i].crew[j].portrait_path</code>) must have a corresponding row in <code>static/data/image-provenance.json</code> with a valid license and a file present on disk. Missing rows or missing files fail the build with a structured diff.</p><p>Asset size cap: <strong>8 MiB per file</strong> (locked by <code>scripts/validate-data.ts</code> post-ADR-047). Aggregate watch via the asset-size CI guard.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li><strong>Operator-first sourcing</strong> is the same discipline the rest of the corpus follows (ADR-046, ADR-051). Inconsistency between fleet and the surrounding routes would be a user-visible quality regression.</li><li><strong>No artist&#39;s impressions for flown vehicles</strong> preserves the editorial honesty that distinguishes Orrery from media surveys; planned-only vehicles carry the <code>artistic-impression: true</code> flag in their license waiver so the rendering is explicit.</li><li><strong>Hand-authored ANATOMY SVGs</strong> are the headline original contribution per PRD-012. They are the reason a curator visits <code>/fleet</code> instead of Wikipedia. The tiered rollout (F.1 marquee first) gets the highest-traffic 20 entries to depth before paying the long-tail authoring cost.</li><li><strong>No-op gracefully</strong> on missing SVGs / portraits keeps editorial honesty: the absence of an image is itself information.</li><li><strong>Build-time integrity</strong> is non-negotiable per ADR-047 — fleet does not get a discount on the provenance rule that governs the rest of the corpus.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Stock photography APIs for hero images</strong> (rejected) — license drift, no agency provenance, biases the corpus toward Western-press aesthetic.</li><li><strong>AI-generated anatomy diagrams</strong> (rejected by ADR-035) — not reproducible, no auditable source, breaks the curated-knowledge promise.</li><li><strong>Silhouette placeholders for missing crew portraits</strong> (rejected) — implies a generic person where the truth is &quot;we don&#39;t have a portrait yet&quot;; replaces information with noise.</li><li><strong>Embed images base64-encoded in JSON</strong> (rejected) — kills HTTP caching, bloats every fetch, makes provenance audit harder.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Every fleet image has a provenance row, a license, and a source agency.</li><li>ANATOMY tab carries hand-authored depth on the 20 entries that anchor the page.</li><li>Failure entries (Challenger, Columbia, Apollo 1, N1) get the same imagery rigour as flown entries — including the crew portraits that turn them from data points into people.</li><li>Asset pipeline reuses ADR-046/047 infrastructure unchanged; no new manifest, no new validator.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>~100 entries no-op the ANATOMY tab at v0.6 ship; long-tail authoring is ongoing.</li><li>Crew-portrait coverage is incomplete for some 1960s Soviet flights where the agency archive doesn&#39;t publish digitised photos at modern resolution — those crew members render as name-only.</li><li>airandspacehistory.com permission is per-image (no blanket licence); each use needs a waiver row.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Hero gallery directory: <code>static/images/fleet-galleries/&lt;id&gt;/{01..NN}.jpg</code>.</li><li>Anatomy SVG: <code>static/diagrams/fleet/&lt;id&gt;.svg</code>. Author with the <code>/science</code> palette; ship sources as the committed file.</li><li>Mission patches: <code>static/images/missions/&lt;mission_id&gt;-patch.png</code>.</li><li>Crew portraits: <code>static/images/crew/&lt;surname&gt;-&lt;initial&gt;.jpg</code>. Naming convention is loose (&quot;aldrin-b.jpg&quot;, &quot;tereshkova-v.jpg&quot;); the <code>portrait_path</code> field is the authoritative reference.</li><li>Audit tooling: <code>scripts/audit-fleet-heroes.ts</code> (read-only), <code>scripts/fix-fleet-heroes.ts</code> (substitution). Run after major fleet content changes; output to <code>docs/provenance/fleet-hero-audit.md</code>.</li><li>License waivers (planned-only vehicles, airandspacehistory.com images): <code>static/data/license-waivers.json</code>, schema in <code>static/data/schemas/license-waivers.schema.json</code>.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li>ADR-035 — Diagram authoring pipeline: hand-drawn SVG, sources committed.</li><li>ADR-046 — Agency-first build-time imagery sourcing.</li><li>ADR-047 — Provenance manifests + license stewardship.</li><li>ADR-051 — Outbound learn-link stewardship.</li><li>ADR-052 — Fleet schema + bidirectional cross-reference contract.</li><li>ADR-054 — Fleet i18n strategy.</li><li>RFC-016 — Spaceflight Fleet · architecture, schema, and dataset boundaries.</li><li>PRD-012 — Spaceflight Fleet product spec.</li></ul>',46)])])}const u=t(s,[["render",r]]);export{g as __pageData,u as default};
